buttons.label:
setMonths(r.value)}
              className={`rounded-full px-3 py-1 text-xs font-medium transition-colors ${
                months === r.value
                  ? "bg-primary text-primary-foreground"
                  : "bg-muted text-muted-foreground hover:bg-muted/80"
              }`}
            >
              {r.label}

addTag(s)}
              className="rounded-full border border-dashed border-border px-2 py-0.5 text-xs text-muted-foreground transition-colors hover:border-primary hover:text-foreground"
            >
              + {s}

cancelMutation.mutate({
                appointmentId: appointment.id,
                reason: reason.trim() || undefined,
              })
            }
            disabled={cancelMutation.isPending}
          >
            {cancelMutation.isPending ? "Cancelling..." : "Yes, Cancel"}

{
            setState({ step: 1 });
            setBooked(false);
          }}
          className="mt-6 text-sm font-medium text-primary underline-offset-4 hover:underline"
        >
          Book another appointment

onSelect(slot)}
              className={cn(
                "rounded-lg border border-border px-3 py-2.5 text-sm font-medium transition-all",
                "hover:border-primary hover:bg-primary/10 hover:text-primary"
              )}
            >
              {formatTime(slot.startAt)}

{
              setStage("email");
              setOtp("");
              setError("");
            }}
            className="w-full text-center text-sm text-muted-foreground hover:text-foreground"
          >
            Use a different email

reward && redeemMutation.mutate({ clientId, rewardId: reward.id })
            }
            disabled={redeemMutation.isPending}
          >
            {redeemMutation.isPending ? "Redeeming..." : "Confirm Redemption"}

redeemMutation.mutate({ clientId, offerId: offer.id })
              }
              disabled={redeemMutation.isPending}
            >
              {redeemMutation.isPending ? "Redeeming..." : "Confirm Redemption"}

setState({
                            step: 3,
                            service: state.service,
                            staffId: selectedStaffId,
                            date: selectedDate,
                            slot,
                          })
                        }
                        className={cn(
                          "rounded-lg border border-border px-3 py-2.5 text-sm font-medium transition-all",
                          "hover:border-primary hover:bg-primary/10 hover:text-primary"
                        )}
                      >
                        {formatTime(slot.startAt)}

{
              setStage("register");
              setOtp("");
              setError("");
            }}
            className="w-full text-center text-sm text-muted-foreground hover:text-foreground"
          >
            Use a different email

onChange(p.value)}
          className={cn(
            "rounded-full px-3 py-1 text-xs font-medium transition-colors",
            value === p.value
              ? "bg-primary text-primary-foreground"
              : "bg-muted text-muted-foreground hover:bg-muted/80"
          )}
        >
          {p.label}
